 32→function filterSections(sections: SectionData[], query: string): SectionData[] {
 33→  if (!query) return sections;
 34→  const lower = query.toLowerCase();
 35→  return sections
 36→    .map(section => ({
 37→      ...section,
 38→      items: section.items.filter(
 39→        item =>
 40→          item.title.toLowerCase().includes(lower) ||
 41→          item.subtitle?.toLowerCase().includes(lower),
 42→      ),
 43→    }))
 44→    .filter(section => section.items.length > 0);
 45→}
 46→
 47→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 48→  if (!query) return colors;
 49→  const lower = query.toLowerCase();
 50→  return colors.filter(
 51→    c =>
 52→      c.title.toLowerCase().includes(lower) ||
 53→      c.subtitle?.toLowerCase().includes(lower),
 54→  );
 55→}
 56→
 57→function flattenItems(sections: SectionData[]): ListItemData[] {
 58→  return sections.flatMap(s => s.items);
 59→}
 60→
 61→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 62→  switch (entry.type) {
 63→    case 'label':
 64→      return (
 65→        <DetailMetadata.Label
 66→          key={index}
 67→          title={entry.title}
 68→          text={entry.text}
 69→        />
 70→      );
 71→    case 'link':
 72→      return (
 73→        <DetailMetadata.Link
 74→          key={index}
 75→          title={entry.title}
 76→          text={entry.text}
 77→          target={entry.target}
 78→        />
 79→      );
 80→    case 'tag-list':
 81→      return (
 82→        <DetailMetadata.TagList key={index} title={entry.title}>
 83→          {entry.tags.map(tag => (
 84→            <DetailMetadata.Tag
 85→              key={tag.text}
 86→              text={tag.text}
 87→              color={tag.color}
 88→            />
 89→          ))}
 90→        </DetailMetadata.TagList>
 91→      );
 92→    case 'separator':
 93→      return <DetailMetadata.Separator key={index} />;
 94→  }
 95→}
 96→
 97→function ColorSwatch({ color }: { color: string }) {
 98→  return (
 99→    <div
100→      className="grid-item__color-swatch"
101→      style={{ backgroundColor: color }}
102→    />
103→  );
104→}
105→
106→function SearchIcon() {
107→  return (
108→    <svg
109→      width="48"
110→      height="48"
111→      viewBox="0 0 48 48"
112→      fill="none"
113→      xmlns="http://www.w3.org/2000/svg"
114→    >
115→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
116→      <line
117→        x1="30"
118→        y1="30"
119→        x2="42"
120→        y2="42"
121→        stroke="currentColor"
122→        strokeWidth="3"
123→        strokeLinecap="round"
124→      />
125→    </svg>
126→  );
127→}
