170→  const [selectedIndex, setSelectedIndex] = useState(0);
171→  const [actionsOpen, setActionsOpen] = useState(false);
172→  const [drilledItem, setDrilledItem] = useState<ListItemData | null>(null);
173→  const [viewMode, setViewMode] = useState<ViewMode>('list');
174→  const [snippetForm, setSnippetForm] =
175→    useState<SnippetFormState>(INITIAL_SNIPPET_FORM);
