import {
  type ReactNode,
  createContext,
  useCallback,
  useContext,
  useMemo,
  useRef,
  useState,
} from 'react';

export interface NavigationEntry {
  title: string;
  component: ReactNode;
}

export type TransitionDirection = 'push' | 'pop' | 'none';

interface NavigationState {
  stack: NavigationEntry[];
  direction: TransitionDirection;
}

export interface NavigationContext {
  push: (title: string, component: ReactNode) => void;
  pop: () => void;
  popToRoot: () => void;
  currentView: ReactNode | null;
  breadcrumbs: { label: string; onBack?: () => void }[];
  canGoBack: boolean;
  direction: TransitionDirection;
  stackDepth: number;
}

const NavContext = createContext<NavigationContext | null>(null);

export const NavigationContextProvider = NavContext.Provider;

export function useNavigation(): NavigationContext {
  const ctx = useContext(NavContext);
  if (!ctx) {
    throw new Error('useNavigation must be used within a NavigationProvider');
  }
  return ctx;
}

export function useNavigationStack(rootTitle: string) {
  const [state, setState] = useState<NavigationState>({
    stack: [],
    direction: 'none',
  });

  const stackRef = useRef(state.stack);
  stackRef.current = state.stack;

  const push = useCallback((title: string, component: ReactNode) => {
    setState(prev => ({
      stack: [...prev.stack, { title, component }],
      direction: 'push',
    }));
  }, []);

  const pop = useCallback(() => {
    if (stackRef.current.length === 0) return;
    setState(prev => ({
      stack: prev.stack.slice(0, -1),
      direction: 'pop',
    }));
  }, []);

  const popToRoot = useCallback(() => {
    if (stackRef.current.length === 0) return;
    setState({
      stack: [],
      direction: 'pop',
    });
  }, []);

  const currentView =
    state.stack.length > 0
      ? state.stack[state.stack.length - 1].component
      : null;

  const canGoBack = state.stack.length > 0;

  const breadcrumbs = useMemo(() => {
    if (state.stack.length === 0) return [];

    const crumbs: { label: string; onBack?: () => void }[] = [
      {
        label: rootTitle,
        onBack: () => {
          setState({ stack: [], direction: 'pop' });
        },
      },
    ];

    for (let i = 0; i < state.stack.length; i++) {
      const entry = state.stack[i];
      const isLast = i === state.stack.length - 1;
      if (isLast) {
        crumbs.push({ label: entry.title });
      } else {
        const targetDepth = i + 1;
        crumbs.push({
          label: entry.title,
          onBack: () => {
            setState(prev => ({
              stack: prev.stack.slice(0, targetDepth),
              direction: 'pop',
            }));
          },
        });
      }
    }

    return crumbs;
  }, [state.stack, rootTitle]);

  const context: NavigationContext = useMemo(
    () => ({
      push,
      pop,
      popToRoot,
      currentView,
      breadcrumbs,
      canGoBack,
      direction: state.direction,
      stackDepth: state.stack.length,
    }),
    [push, pop, popToRoot, currentView, breadcrumbs, canGoBack, state.direction, state.stack.length],
  );

  return context;
}

