  1→import { useCallback, useEffect, useMemo, useState } from 'react';
  2→import { ActionPanel } from './components/action_panel/action_panel';
  3→import { Alert } from './components/alert/alert';
  4→import { CommandPalette } from './components/command_palette/command_palette';
  5→import { Detail } from './components/detail/detail';
  6→import { DetailMetadata } from './components/detail/detail_metadata';
  7→import { EmptyState } from './components/empty_state/empty_state';
  8→import {
  9→  Form,
 10→  FormCheckbox,
 11→  FormDatePicker,
 12→  FormDropdown,
 13→  FormTextArea,
 14→  FormTextField,
 15→} from './components/form';
 16→import { Grid, GridItem } from './components/grid';
 17→import { Kbd } from './components/kbd/kbd';
 18→import { List, ListItem, ListSection } from './components/list';
 19→import { SearchBar } from './components/search_bar/search_bar';
 20→import { ToastContainer } from './components/toast/toast_container';
 21→import { MOCK_COLORS, MOCK_SECTIONS } from './data/mock_data';
 22→import { useAlert } from './hooks/use_alert';
 23→import {
 24→  NavigationContextProvider,
 25→  useNavigationStack,
 26→} from './hooks/use_navigation';
 27→import { useToast } from './hooks/use_toast';
 28→import type {
 29→  ColorItemData,
 30→  ListItemData,
 31→  ListItemMetadataEntry,
 32→  SectionData,
 33→} from './types';
 34→
 35→function filterSections(sections: SectionData[], query: string): SectionData[] {
 36→  if (!query) return sections;
 37→  const lower = query.toLowerCase();
 38→  return sections
 39→    .map(section => ({
 40→      ...section,
 41→      items: section.items.filter(
 42→        item =>
 43→          item.title.toLowerCase().includes(lower) ||
 44→          item.subtitle?.toLowerCase().includes(lower),
 45→      ),
 46→    }))
 47→    .filter(section => section.items.length > 0);
 48→}
 49→
 50→function filterColors(colors: ColorItemData[], query: string): ColorItemData[] {
 51→  if (!query) return colors;
 52→  const lower = query.toLowerCase();
 53→  return colors.filter(
 54→    c =>
 55→      c.title.toLowerCase().includes(lower) ||
 56→      c.subtitle?.toLowerCase().includes(lower),
 57→  );
 58→}
 59→
 60→function flattenItems(sections: SectionData[]): ListItemData[] {
 61→  return sections.flatMap(s => s.items);
 62→}
 63→
 64→function renderMetadataEntry(entry: ListItemMetadataEntry, index: number) {
 65→  switch (entry.type) {
 66→    case 'label':
 67→      return (
 68→        <DetailMetadata.Label
 69→          key={index}
 70→          title={entry.title}
 71→          text={entry.text}
 72→        />
 73→      );
 74→    case 'link':
 75→      return (
 76→        <DetailMetadata.Link
 77→          key={index}
 78→          title={entry.title}
 79→          text={entry.text}
 80→          target={entry.target}
 81→        />
 82→      );
 83→    case 'tag-list':
 84→      return (
 85→        <DetailMetadata.TagList key={index} title={entry.title}>
 86→          {entry.tags.map(tag => (
 87→            <DetailMetadata.Tag
 88→              key={tag.text}
 89→              text={tag.text}
 90→              color={tag.color}
 91→            />
 92→          ))}
 93→        </DetailMetadata.TagList>
 94→      );
 95→    case 'separator':
 96→      return <DetailMetadata.Separator key={index} />;
 97→  }
 98→}
 99→
100→function ColorSwatch({ color }: { color: string }) {
101→  return (
102→    <div
103→      className="grid-item__color-swatch"
104→      style={{ backgroundColor: color }}
105→    />
106→  );
107→}
108→
109→function SearchIcon() {
110→  return (
111→    <svg
112→      width="48"
113→      height="48"
114→      viewBox="0 0 48 48"
115→      fill="none"
116→      xmlns="http://www.w3.org/2000/svg"
117→    >
118→      <circle cx="21" cy="21" r="12" stroke="currentColor" strokeWidth="3" />
119→      <line
120→        x1="30"
121→        y1="30"
122→        x2="42"
123→        y2="42"
124→        stroke="currentColor"
125→        strokeWidth="3"
126→        strokeLinecap="round"
127→      />
128→    </svg>
129→  );
130→}
131→
132→interface SnippetFormState {
133→  name: string;
134→  keyword: string;
135→  snippet: string;
136→  category: string;
137→  isShared: boolean;
138→  expiresAt: string;
139→}
140→
141→const INITIAL_SNIPPET_FORM: SnippetFormState = {
142→  name: '',
143→  keyword: '',
144→  snippet: '',
145→  category: 'general',
146→  isShared: false,
147→  expiresAt: '',
148→};
149→
150→const SNIPPET_CATEGORIES = [
151→  { label: 'General', value: 'general' },
152→  { label: 'Code', value: 'code' },
153→  { label: 'Email', value: 'email' },
154→  { label: 'Template', value: 'template' },
155→];
156→
157→interface ColorPickerViewProps {
158→  onCopyColor: (color: ColorItemData) => void;
159→}
160→
161→function ColorPickerView({ onCopyColor }: ColorPickerViewProps) {
162→  const [query, setQuery] = useState('');
163→  const [selectedIndex, setSelectedIndex] = useState(0);
164→
165→  const filteredColors = useMemo(
166→    () => filterColors(MOCK_COLORS, query),
167→    [query],
168→  );
169→
170→  const handleActiveIndexChange = useCallback((index: number) => {
171→    setSelectedIndex(index);
172→  }, []);
173→
174→  const handleGridAction = useCallback(
175→    (index: number) => {
176→      const color = filteredColors[index];
177→      if (color) {
178→        onCopyColor(color);
179→      }
180→    },
181→    [filteredColors, onCopyColor],
182→  );
183→
184→  if (filteredColors.length === 0) {
185→    return (
186→      <EmptyState
187→        icon={<SearchIcon />}
188→        title="No Colors"
189→        description="Try a different search term"
190→      />
191→    );
192→  }
193→
194→  return (
195→    <Grid
196→      itemCount={filteredColors.length}
197→      columns={4}
198→      onActiveIndexChange={handleActiveIndexChange}
199→      onAction={handleGridAction}
200→    >
201→      {filteredColors.map((color, index) => (
202→        <GridItem
203→          key={color.id}
204→          index={index}
205→          icon={<ColorSwatch color={color.color} />}
206→          title={color.title}
207→          subtitle={color.subtitle}
208→        />
209→      ))}
210→    </Grid>
211→  );
212→}
213→
214→interface CreateSnippetViewProps {
215→  onSubmit: (form: SnippetFormState) => void;
216→}
217→
218→function CreateSnippetView({ onSubmit }: CreateSnippetViewProps) {
219→  const [snippetForm, setSnippetForm] =
220→    useState<SnippetFormState>(INITIAL_SNIPPET_FORM);
221→  const [formErrors, setFormErrors] = useState<
222→    Partial<Record<keyof SnippetFormState, string>>
223→  >({});
224→
225→  const handleSubmit = useCallback(() => {
226→    const errors: Partial<Record<keyof SnippetFormState, string>> = {};
227→    if (!snippetForm.name.trim()) {
228→      errors.name = 'Name is required';
229→    }
230→    if (!snippetForm.snippet.trim()) {
231→      errors.snippet = 'Snippet content is required';
232→    }
233→    setFormErrors(errors);
234→    if (Object.keys(errors).length > 0) {
235→      return;
236→    }
237→    onSubmit(snippetForm);
238→  }, [snippetForm, onSubmit]);
239→
240→  useEffect(() => {
241→    function handleKeyDown(e: KeyboardEvent) {
242→      if (e.key === 'Enter' && e.metaKey) {
243→        e.preventDefault();
244→        handleSubmit();
245→      }
246→    }
247→    window.addEventListener('keydown', handleKeyDown);
248→    return () => window.removeEventListener('keydown', handleKeyDown);
249→  }, [handleSubmit]);
250→
251→  return (
252→    <Form onSubmit={handleSubmit}>
253→      <FormTextField
254→        label="Name"
255→        value={snippetForm.name}
256→        onChange={v =>
257→          setSnippetForm(prev => ({ ...prev, name: v }))
258→        }
259→        placeholder="e.g. Email Signature"
260→        error={formErrors.name}
261→        autoFocus
262→      />
263→      <FormTextField
264→        label="Keyword"
265→        value={snippetForm.keyword}
266→        onChange={v =>
267→          setSnippetForm(prev => ({ ...prev, keyword: v }))
268→        }
269→        placeholder="e.g. !sig"
270→        description="Type this to expand the snippet"
271→      />
272→      <FormDropdown
273→        label="Category"
274→        value={snippetForm.category}
275→        onChange={v =>
276→          setSnippetForm(prev => ({ ...prev, category: v }))
277→        }
278→        options={SNIPPET_CATEGORIES}
279→        placeholder="Select a category"
280→      />
281→      <FormTextArea
282→        label="Snippet"
283→        value={snippetForm.snippet}
284→        onChange={v =>
285→          setSnippetForm(prev => ({ ...prev, snippet: v }))
286→        }
287→        placeholder="Enter your snippet content..."
288→        error={formErrors.snippet}
289→        rows={5}
290→      />
291→      <FormCheckbox
292→        label="Share with team"
293→        checked={snippetForm.isShared}
294→        onChange={v =>
295→          setSnippetForm(prev => ({ ...prev, isShared: v }))
296→        }
297→        description="Make this snippet available to your team members"
298→      />
299→      <FormDatePicker
300→        label="Expires"
301→        value={snippetForm.expiresAt}
302→        onChange={v =>
303→          setSnippetForm(prev => ({ ...prev, expiresAt: v }))
304→        }
305→        description="Optional expiration date"
306→      />
307→    </Form>
308→  );
309→}
310→
311→type ActiveView = 'root' | 'grid' | 'form' | 'detail';
312→
313→export function App() {
314→  const [query, setQuery] = useState('');
315→  const [selectedIndex, setSelectedIndex] = useState(0);
316→  const [actionsOpen, setActionsOpen] = useState(false);
317→  const [activeView, setActiveView] = useState<ActiveView>('root');
318→  const { toasts, show: showToast, hide: hideToast } = useToast();
319→  const { alertState, confirmAlert, dismiss: dismissAlert } = useAlert();
320→  const nav = useNavigationStack('Raycast');
321→
322→  const filtered = useMemo(() => filterSections(MOCK_SECTIONS, query), [query]);
323→  const allItems = useMemo(() => flattenItems(filtered), [filtered]);
324→
325→  const selectedItem =
326→    activeView === 'root' ? allItems[selectedIndex] : undefined;
327→
328→  const handleQueryChange = useCallback((value: string) => {
329→    setQuery(value);
330→    setSelectedIndex(0);
331→    setActionsOpen(false);
332→  }, []);
333→
334→  const handleActiveIndexChange = useCallback((index: number) => {
335→    setSelectedIndex(index);
336→    setActionsOpen(false);
337→  }, []);
338→
339→  const handleCopyColor = useCallback(
340→    (color: ColorItemData) => {
341→      showToast({
342→        style: 'info',
343→        title: 'Copied color',
344→        message: color.color,
345→      });
346→    },
347→    [showToast],
348→  );
349→
350→  const handleSnippetSubmit = useCallback(
351→    (form: SnippetFormState) => {
352→      showToast({
353→        style: 'success',
354→        title: 'Snippet Created',
355→        message: form.name,
356→      });
357→      nav.pop();
358→      setActiveView('root');
359→      setQuery('');
360→      setSelectedIndex(0);
361→      setActionsOpen(false);
362→    },
363→    [showToast, nav],
364→  );
365→
366→  const handleDrillIn = useCallback(() => {
367→    const item = allItems[selectedIndex];
368→    if (!item) return;
369→
370→    setActionsOpen(false);
371→
372→    if (item.id === 'color-picker') {
373→      setActiveView('grid');
374→      nav.push(
375→        'Color Picker',
376→        <ColorPickerView onCopyColor={handleCopyColor} />,
377→      );
378→      setQuery('');
379→      setSelectedIndex(0);
380→      showToast({ style: 'success', title: 'Opened Color Picker' });
381→    } else if (item.detail) {
382→      setActiveView('detail');
383→      nav.push(
384→        item.title,
385→        <div className="command-palette__body--has-detail" style={{ display: 'flex', flex: 1, minHeight: 0, overflow: 'hidden' }}>
