import {
  createContext,
  useCallback,
  useContext,
  useMemo,
  useRef,
  useState,
} from 'react';

export interface NavigationEntry<T = unknown> {
  title: string;
  data: T;
}

export type TransitionDirection = 'push' | 'pop' | 'none';

interface NavigationState<T> {
  stack: NavigationEntry<T>[];
  direction: TransitionDirection;
}

export interface NavigationContext<T = unknown> {
  push: (title: string, data: T) => void;
  pop: () => void;
  popToRoot: () => void;
  currentEntry: NavigationEntry<T> | null;
  breadcrumbs: { label: string; onBack?: () => void }[];
  canGoBack: boolean;
  direction: TransitionDirection;
  stackDepth: number;
}

const NavContext = createContext<NavigationContext | null>(null);

export const NavigationContextProvider = NavContext.Provider;

export function useNavigation<T = unknown>(): NavigationContext<T> {
  const ctx = useContext(NavContext);
  if (!ctx) {
    throw new Error('useNavigation must be used within a NavigationProvider');
  }
  return ctx as NavigationContext<T>;
}

export function useNavigationStack<T = unknown>(rootTitle: string): NavigationContext<T> {
  const [state, setState] = useState<NavigationState<T>>({
    stack: [],
    direction: 'none',
  });

  const stackRef = useRef(state.stack);
  stackRef.current = state.stack;

  const push = useCallback((title: string, data: T) => {
    setState(prev => ({
      stack: [...prev.stack, { title, data }],
      direction: 'push',
    }));
  }, []);

  const pop = useCallback(() => {
    if (stackRef.current.length === 0) return;
    setState(prev => ({
      stack: prev.stack.slice(0, -1),
      direction: 'pop',
    }));
  }, []);

  const popToRoot = useCallback(() => {
    if (stackRef.current.length === 0) return;
    setState({
      stack: [],
      direction: 'pop',
    });
  }, []);

  const currentEntry =
    state.stack.length > 0
      ? state.stack[state.stack.length - 1]
      : null;

  const canGoBack = state.stack.length > 0;

  const breadcrumbs = useMemo(() => {
    if (state.stack.length === 0) return [];

    const crumbs: { label: string; onBack?: () => void }[] = [
      {
        label: rootTitle,
        onBack: () => {
          setState({ stack: [], direction: 'pop' });
        },
      },
    ];

    for (let i = 0; i < state.stack.length; i++) {
      const entry = state.stack[i];
      const isLast = i === state.stack.length - 1;
      if (isLast) {
        crumbs.push({ label: entry.title });
      } else {
        const targetDepth = i + 1;
        crumbs.push({
          label: entry.title,
          onBack: () => {
            setState(prev => ({
              stack: prev.stack.slice(0, targetDepth),
              direction: 'pop',
            }));
          },
        });
      }
    }

    return crumbs;
  }, [state.stack, rootTitle]);

  return useMemo(
    () => ({
      push,
      pop,
      popToRoot,
      currentEntry,
      breadcrumbs,
      canGoBack,
      direction: state.direction,
      stackDepth: state.stack.length,
    }),
    [push, pop, popToRoot, currentEntry, breadcrumbs, canGoBack, state.direction, state.stack.length],
  );
}

