    [showToast, nav],
  );

  const handleDrillIn = useCallback(() => {
    const item = allItems[selectedIndex];
    if (!item) return;

    setActionsOpen(false);

    if (item.id === 'color-picker') {
      nav.push('Color Picker', { type: 'grid' });
      setQuery('');
      setSelectedIndex(0);
      showToast({ style: 'success', title: 'Opened Color Picker' });
    } else if (item.detail) {
      nav.push(item.title, { type: 'detail', item });
      setQuery('');
      showToast({ style: 'success', title: `Opened ${item.title}` });
    } else {
      showToast({ style: 'success', title: `Opened ${item.title}` });
