  }, [viewType, handleOpenCreateSnippet]);

  const detail = selectedItem?.detail;

  const dropdownActions = useMemo(
    () => [
      {
        label: 'Open',
        shortcut: <Kbd keys={['↵']} />,
        onClick: () => {
          if (selectedItem) {
            showToast({
