      {
        label: 'Create Snippet',
        shortcut: <Kbd keys={['⌘', 'N']} />,
        onClick: handleOpenCreateSnippet,
      },
      {
        label: 'Delete',
        shortcut: <Kbd keys={['⌘', '⌫']} />,
        onClick: () => {
          if (!selectedItem) return;
          const itemTitle = selectedItem.title;
          setActionsOpen(false);
          confirmAlert({
