                  cy="16"
                  r="14"
                  fill="currentColor"
                  opacity="0.15"
                />
                <path
                  d="M12 13V22M16 13V22M20 13V22M10 10H22M13 10V9C13 8.45 13.45 8 14 8H18C18.55 8 19 8.45 19 9V10"
                  stroke="currentColor"
                  strokeWidth="1.5"
                  strokeLinecap="round"
                  strokeLinejoin="round"
                />
              </svg>
            ),
            primaryAction: {
              label: 'Delete',
              style: 'destructive',
              onAction: () => {
                showToast({
                  style: 'error',
                  title: 'Deleted',
                  message: itemTitle,
                });
              },
            },
            dismissAction: {
              label: 'Cancel',
              style: 'cancel',
              onAction: () => {},
            },
          });
        },
      },
    ],
    [selectedItem, showToast, handleOpenCreateSnippet, confirmAlert],
  );

  const activeDescendantId =
    viewType === 'root' && allItems.length > 0
